import React, { useEffect, useState } from "react";
import axios from "axios";
import "./Report.css"; // CSS riêng cho bảng và card

const Report = () => {
  const [monthlyRevenue, setMonthlyRevenue] = useState([]);
  const [yearlyRevenue, setYearlyRevenue] = useState([]);
  const [topCustomers, setTopCustomers] = useState([]);
  const [roomUsage, setRoomUsage] = useState([]);
  const [viewMode, setViewMode] = useState("monthly");

  const apiBase = "http://localhost:5000/api/report";

  useEffect(() => {
    fetchRevenue();
    fetchTopCustomers();
    fetchRoomUsage();
  }, []);

  const fetchRevenue = async () => {
    try {
      const res = await axios.get(`${apiBase}/revenue`);
      setMonthlyRevenue(res.data.monthly);
      setYearlyRevenue(res.data.yearly);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải báo cáo doanh thu");
    }
  };

  const fetchTopCustomers = async () => {
    try {
      const res = await axios.get(`${apiBase}/topcustomer`);
      setTopCustomers(res.data);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải top khách hàng");
    }
  };

  const fetchRoomUsage = async () => {
    try {
      const res = await axios.get(`${apiBase}/roomusage`);
      setRoomUsage(res.data);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải công suất phòng");
    }
  };

  const Card = ({ title, children }) => (
    <div className="card">
      <h2 className="card-title">{title}</h2>
      {children}
    </div>
  );

  const renderRevenueTable = () => {
    if (viewMode === "monthly") {
      if (!monthlyRevenue.length) return <p>Chưa có dữ liệu</p>;
      return (
        <table className="table">
          <thead className="thead-blue">
            <tr>
              <th>Năm</th>
              <th>Tháng</th>
              <th>Doanh thu</th>
            </tr>
          </thead>
          <tbody>
            {monthlyRevenue.map((row, idx) => (
              <tr key={idx} className={idx % 2 === 0 ? "even" : "odd"}>
                <td>{row.Nam}</td>
                <td>{row.Thang}</td>
                <td>{row.DoanhThu}</td>
              </tr>
            ))}
          </tbody>
        </table>
      );
    } else {
      if (!yearlyRevenue.length) return <p>Chưa có dữ liệu</p>;
      return (
        <table className="table">
          <thead className="thead-blue">
            <tr>
              <th>Năm</th>
              <th>Doanh thu</th>
            </tr>
          </thead>
          <tbody>
            {yearlyRevenue.map((row, idx) => (
              <tr key={idx} className={idx % 2 === 0 ? "even" : "odd"}>
                <td>{row.Nam}</td>
                <td>{row.DoanhThu}</td>
              </tr>
            ))}
          </tbody>
        </table>
      );
    }
  };

  const renderTopCustomersTable = () => {
    if (!topCustomers.length) return <p>Chưa có dữ liệu</p>;
    return (
      <table className="table">
        <thead className="thead-green">
          <tr>
            <th>Mã KH</th>
            <th>Họ tên</th>
            <th>Số lần đặt</th>
            <th>Tổng chi tiêu</th>
          </tr>
        </thead>
        <tbody>
          {topCustomers.map((row, idx) => (
            <tr key={idx} className={idx % 2 === 0 ? "even" : "odd"}>
              <td>{row.MaKH}</td>
              <td>{row.HoTen}</td>
              <td>{row.SoLanDat}</td>
              <td>{row.TongChiTieu}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  const renderRoomUsageTable = () => {
    if (!roomUsage.length) return <p>Chưa có dữ liệu</p>;
    return (
      <table className="table">
        <thead className="thead-yellow">
          <tr>
            <th>Phòng số</th>
            <th>Số lần thuê</th>
          </tr>
        </thead>
        <tbody>
          {roomUsage.map((row, idx) => (
            <tr key={idx} className={idx % 2 === 0 ? "even" : "odd"}>
              <td>{row.PhongSo}</td>
              <td>{row.SoLanThue}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  return (
    <div className="report-container">
      <h1>Báo cáo tổng hợp</h1>

      <Card title="Doanh thu">
        <div style={{ marginBottom: "10px" }}>
          <label style={{ marginRight: "10px" }}>Xem theo:</label>
          <select
            value={viewMode}
            onChange={(e) => setViewMode(e.target.value)}
          >
            <option value="monthly">Tháng</option>
            <option value="yearly">Năm</option>
          </select>
        </div>
        {renderRevenueTable()}
      </Card>

      <Card title="Top khách hàng">{renderTopCustomersTable()}</Card>
      <Card title="Công suất phòng">{renderRoomUsageTable()}</Card>
    </div>
  );
};

export default Report;
